body:
I wrote a simplified version of the buffer as described below: 
takes 1 byte inputs and outputs 3 bytes, 
stores 8 bytes of data

I expect buffer to wrap around and output last, first and second bytes after array index rdPntr+1 and rdPntr+2 overflow(ie. o_data[23:0] = "070001"). **Verilator** and **simulator of vivado** give the expected output. However, **iverilog** displays "07xxxx" in wave trace as i attached below.

code: 
```
module lineBuffer(
input   i_clk,
input   i_rst,
input [7:0] i_data,
input   i_data_valid,
output [23:0] o_data,
input i_rd_data
);

reg [7:0] line [7:0]; //line buffer
reg [2:0] wrPntr;
reg [2:0] rdPntr;

always @(posedge i_clk)
begin
    if(i_data_valid)
        line[wrPntr] <= i_data;
end

always @(posedge i_clk)
begin
    if(i_rst)
        wrPntr <= 'd0;
    else if(i_data_valid)
        wrPntr <= wrPntr + 'd1;
end

assign o_data = {line[rdPntr],line[rdPntr+1],line[rdPntr+2]};

always @(posedge i_clk)
begin
    if(i_rst)
        rdPntr <= 'd0;
    else if(i_rd_data)
        rdPntr <= rdPntr + 'd1;
end


endmodule
```
